queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?adventure_movies a :Adventure_Movies .
    ?adventure_movies p:title ?title .
    ?adventure_movies p:Director ?director_f .
    FILTER(STR(?director_f) = "Sofia Martinez")
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?action_movies a :Action_Movies .
    ?action_movies p:title ?title .
    ?action_movies p:Director ?director_f .
    FILTER(STR(?director_f) = "Sofia Martinez")
    BIND(?title AS ?o0)
  }
}

